import unittest
from slug import slugify
class T(unittest.TestCase):
    def test_slugify(self):
        self.assertEqual(slugify(" Hello, Kcode!! "), "hello-kcode")
        self.assertEqual(slugify("A  B"), "a-b")
if __name__ == "__main__": unittest.main()

